from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
import os
import hmac

app = Flask(__name__)

LOG_PATH = os.environ.get("AUTH_LOG_PATH", "application.log")

logger = logging.getLogger("auth_logger")
logger.setLevel(logging.INFO)
handler = RotatingFileHandler(LOG_PATH, maxBytes=10 * 1024 * 1024, backupCount=5)
formatter = logging.Formatter(
    fmt="%(asctime)s %(levelname)s %(message)s",
    datefmt="%Y-%m-%d %H:%M:%S",
)
handler.setFormatter(formatter)
logger.addHandler(handler)
logger.propagate = False

USERS = {
    "alice": {"password": "password123", "email": "alice@example.com"},
    "bob": {"password": "secret", "email": "bob@example.com"},
}

def get_client_ip(req):
    xff = req.headers.get("X-Forwarded-For", "")
    if xff:
        return xff.split(",")[0].strip()
    return req.remote_addr or ""

def safe_str(v):
    if v is None:
        return ""
    try:
        return str(v)
    except Exception:
        return ""

def log_attempt(username, password, email, success, reason=""):
    ip = get_client_ip(request)
    ua = request.headers.get("User-Agent", "")
    logger.info(
        'login_attempt success=%s reason="%s" username="%s" password="%s" email="%s" ip="%s" user_agent="%s"',
        success,
        safe_str(reason),
        safe_str(username),
        safe_str(password),
        safe_str(email),
        safe_str(ip),
        safe_str(ua),
    )

@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "")
    password = data.get("password", "")
    email = data.get("email", "")

    user = USERS.get(username)
    if not user:
        log_attempt(username, password, email, False, "user_not_found")
        return jsonify({"ok": False, "error": "Invalid credentials"}), 401

    expected_email = user.get("email", "")
    expected_password = user.get("password", "")

    if email and expected_email and not hmac.compare_digest(safe_str(email), safe_str(expected_email)):
        log_attempt(username, password, email, False, "email_mismatch")
        return jsonify({"ok": False, "error": "Invalid credentials"}), 401

    if not hmac.compare_digest(safe_str(password), safe_str(expected_password)):
        log_attempt(username, password, email or expected_email, False, "bad_password")
        return jsonify({"ok": False, "error": "Invalid credentials"}), 401

    log_attempt(username, password, email or expected_email, True, "authenticated")
    return jsonify({"ok": True, "message": "Authenticated"}), 200

